request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT DISTINCT
  ?model
  ?modelName
  ?created
WHERE {
  ?org a bboExt:Organization ;
       tai:organizationId "985f88f59e8b4962a0a2c2fec001b6d1" .

  ?model a bboExt:Model ;
         tai:belongsTo ?org ;
         bbo:name ?modelName ;
         tai:modelCreated ?created .

  ?definitions tai:belongsTo ?model .
  ?choreo a bboExt:Choreography ;
          tai:belongsTo ?definitions .

  ?task a bboExt:ChoreographyTask ;
        tai:belongsTo ?choreo ;
        bbo:name ?taskName .

  FILTER(CONTAINS(LCASE(STR(?taskName)), "buy") || CONTAINS(LCASE(STR(?taskName)), "purchase") || CONTAINS(LCASE(STR(?taskName)), "order") || CONTAINS(LCASE(STR(?taskName)), "product") || CONTAINS(LCASE(STR(?taskName)), "shopping"))
}
ORDER BY DESC(?created)
LIMIT 25
